files.css:
.bar {
  display: flex;
  gap: 1rem;
  padding: 0.75rem 1rem;
  background: #1e293b;
  font-family: sans-serif;
}
.bar a { color: #93c5fd; text-decoration: none; }

.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  padding: 1rem;
  font-family: sans-serif;
}
.item {
  background: #dbeafe;
  padding: 2rem;
  text-align: center;
  border-radius: 8px;
}

body { margin: 0; font-family: system-ui, sans-serif; }
.topnav { display: flex; gap: 1rem; padding: 0.75rem 1rem; background: #1e293b; }
.topnav a { color: #93c5fd; text-decoration: none; }
.layout { display: grid; grid-template-columns: 160px 1fr; min-height: 180px; }
.sidebar { background: #dbeafe; padding: 1rem; }
.sidebar a { display: block; color: #1e40af; text-decoration: none; margin-bottom: 0.5rem; }
main { padding: 1rem; }
main h2 { margin-top: 0; color: #1e293b; }
@media (max-width: 520px) {
  .layout { grid-template-columns: 1fr; }
  .sidebar { display: flex; flex-wrap: wrap; gap: 0.75rem; }
  .sidebar a { margin-bottom: 0; }
}

starter.css:
.center-wrap {
  min-height: 200px;
  /* add flex centering */
}
.centered {
  padding: 1.5rem 2rem;
  background: #22c55e;
  color: #fff;
  border-radius: 8px;
  font-family: sans-serif;
}
